import{_ as a,o,c as t,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Guide to Facebook Attribution Changes for iOS 14","description":"","frontmatter":{"title":"Guide to Facebook Attribution Changes for iOS 14","slug":"facebook-ios-14"},"headers":[],"relativePath":"marketer-hub/facebook-ios-14.md","filePath":"marketer-hub/facebook-ios-14.md"}'),s={name:"marketer-hub/facebook-ios-14.md"};function i(r,e,l,p,c,d){return o(),t("div",null,[...e[0]||(e[0]=[n('<p>In January, Facebook provided an updated response on how they’ll be handling IDFA and attribution when Apple enforces the ATT framework in an upcoming iOS 14 release. Facebook’s guidance for app advertiser’s can be found <a href="https://developers.facebook.com/blog/post/2021/01/19/actions-app-advertisers-developers/" target="_blank" rel="noreferrer">here</a> and for web advertiser’s can be found <a href="https://developers.facebook.com/blog/post/2020/12/16/preparing-partners-ios-14-mobile-web-advertising" target="_blank" rel="noreferrer">here</a>.</p><p>Branch customers running Mobile App Install (MAI) and App Event Optimization (AEO) campaigns on Facebook will need to update their Branch SDK (this was already required for SKAdNetwork compatibility) and Facebook SDK (if used). Advertisers will also need to take some Facebook-specific actions listed below, including setting up a new Facebook ad account for iOS 14.</p><p>Our current understanding is that Facebook&#39;s web attribution changes will not affect Branch or the use of Branch Links in web campaign types, but we are working with Facebook to understand the full impact of these changes.</p><p>Facebook is planning on making SKAN data available via the Ad Insights API soon. Before then, MMPs will not have visibility into this data for our mutual advertisers.</p><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><p><strong>Facebook will ask users for tracking consent via the ATT prompt</strong></p><p>Apple’s iOS 14 will give apps the ability to ask users for tracking consent, including access to IDFAs. Although previously they had announced that they would not be using Apple&#39;s ATT framework, Facebook decided they will be asking users for tracking consent via the ATT prompt, meaning Facebook will also have access to user IDFAs within their family of apps (Facebook, WhatsApp, Instagram, Messenger).</p><p><strong>Facebook will use a Conversion Bit Schema to map SKAdNetwork conversion-values</strong></p><p>If the customer is using the Facebook SDK (or any other implementation option) for SKAdNetwork, the conversion value mapping will be configured using Facebook&#39;s Events Manager.</p><p>If using the Branch SDK for SKAdNetwork, Facebook will use a Branch-provided API endpoint to pull the customer&#39;s SKAdNetwork Conversion Bit Schema (the mapping of SKAN conversion-value events). As of late January, we are in the final stages of testing this new API with Facebook. Once tests are complete, FB and Branch will be able to start test campaigns with this new functionality with our mutual advertisers.</p><p><strong>Facebook will continue to provide support for Mobile App Install (MAI) and App Event Optimization (AEO) campaigns</strong></p><p>Advertisers should update their app for iOS 14 by using either a new version of the Facebook SDK, or an updated SDK from a compatible MMP.</p><p>The updated Facebook SDK (v8.1 or above) will also enable apps to send a flag to Facebook to restrict data use on a per-event basis. If advertisers decide not to send Facebook a flag indicating an iOS 14 event is opted-in for tracking, Facebook will restrict their use of that event. For advertisers relying on the Facebook SDK to send App Events, only the updated SDK version allows events from users on iOS 14 to be used for optimizing app ads.</p><p>For advertisers relying on the Branch SDK to send App Events to Facebook, Branch will use the value of the device&#39;s limited_ad_tracking parameter to determine whether events should be sent to Facebook. This parameter is set based on the user&#39;s response to the ATT prompt for that app.</p><h2 id="facebook-s-recommendations-to-customers" tabindex="-1">Facebook&#39;s Recommendations to Customers <a class="header-anchor" href="#facebook-s-recommendations-to-customers" aria-label="Permalink to &quot;Facebook&#39;s Recommendations to Customers&quot;">​</a></h2><ul><li><p>Update to the latest versions of the Facebook and/or Branch SDKs, depending on which SDKs an advertiser has integrated into their app:</p><ol><li><strong>Only the updated Facebook SDK</strong>: Facebook can provide both MAI and AEO campaigns.</li><li><strong>Both updated Facebook SDK + Branch SDK</strong>: Facebook can provide MAI and AEO campaigns as long as events are funneled through the FB SDK.</li><li><strong>Only the Branch SDK</strong>: MAI and AEO campaigns will be enabled once Branch completes testing of Facebook&#39;s new Conversion Bit Schema (sending a JSON mapping of conversion values/events to an API).</li></ol></li><li><p>Plan to operate all iOS 14 campaigns using:</p><ul><li>1 Ad Account</li><li>9 Campaigns</li><li>5 Ad Sets</li></ul></li><li><p>Implement the new “Advertiser Tracking Enabled” flag to enable matching for people using iOS 14.</p><ul><li>For events collected via the Branch SDK, this flag is controlled by the value of the device&#39;s limited_ad_tracking parameter. This parameter is set based on the user&#39;s response to the ATT prompt for that app.</li></ul></li></ul><h3 id="faqs" tabindex="-1">FAQs <a class="header-anchor" href="#faqs" aria-label="Permalink to &quot;FAQs&quot;">​</a></h3><p><a href="./ios-14-faqs.html">Facebook iOS 14 FAQs</a></p>',18)])])}const b=a(s,[["render",i]]);export{u as __pageData,b as default};
